import { useState } from 'react'
import { TopBar } from '@/components/layout/TopBar'
import { FlowTable } from '@/components/flows/FlowTable'
import { FlowRuleEditor } from '@/components/flows/FlowRuleEditor'
import { useFlowStore } from '@/stores/flowStore'

export const FlowsPage = () => {
  const [showEditor, setShowEditor] = useState(false)
  const flows = useFlowStore((s) => s.flows)
  const activeFlows = flows.filter((f) => f.state === 'ADDED').length

  return (
    <div className="flex flex-col h-screen overflow-hidden">
      <TopBar
        title="Flow Rules"
        subtitle={`${activeFlows} active · ${flows.length} total`}
      />

      <div className="flex-1 overflow-y-auto p-4">
        <FlowTable onAddFlow={() => setShowEditor(true)} />
      </div>

      {showEditor && (
        <FlowRuleEditor onClose={() => setShowEditor(false)} />
      )}
    </div>
  )
}
