import { useEffect } from 'react'
import { Routes, Route } from 'react-router-dom'
import { AppShell } from '@/components/layout/AppShell'
import { DashboardPage  } from '@/pages/DashboardPage'
import { TopologyPage   } from '@/pages/TopologyPage'
import { DevicesPage    } from '@/pages/DevicesPage'
import { FlowsPage      } from '@/pages/FlowsPage'
import { MetricsPage    } from '@/pages/MetricsPage'
import { ExperimentsPage} from '@/pages/ExperimentsPage'
import { AlertsPage     } from '@/pages/AlertsPage'
import { SettingsPage   } from '@/pages/SettingsPage'
import { useWebSocketManager } from '@/hooks/useWebSocket'
import { startMockSimulation } from '@/utils/mockData'

const DEMO_MODE = true  // Set false to connect to a real ONOS backend

const App = () => {
  // Start WebSocket connection (connects to mock or real backend)
  useWebSocketManager()

  // Start mock simulation in demo mode
  useEffect(() => {
    if (DEMO_MODE) {
      startMockSimulation()
    }
  }, [])

  return (
    <Routes>
      <Route element={<AppShell />}>
        <Route path="/"            element={<DashboardPage />} />
        <Route path="/topology"    element={<TopologyPage />} />
        <Route path="/devices"     element={<DevicesPage />} />
        <Route path="/flows"       element={<FlowsPage />} />
        <Route path="/metrics"     element={<MetricsPage />} />
        <Route path="/experiments" element={<ExperimentsPage />} />
        <Route path="/alerts"      element={<AlertsPage />} />
        <Route path="/settings"    element={<SettingsPage />} />
      </Route>
    </Routes>
  )
}

export default App
